  <section class="overflow-hidden rounded-xl border border-border bg-card text-card-foreground shadow-sm max-[640px]:rounded-lg"><header class="flex items-center justify-between gap-4 border-b border-border px-5 py-4 max-[640px]:px-4"><div class="grid gap-0.5"><h2 class="m-0 text-base font-semibold tracking-[-0.01em]">Registered listeners</h2><p class="m-0 text-xs text-muted-foreground">Core and extension listeners currently visible to the dispatcher.</p></div><span class="hidden rounded-full bg-muted px-2 py-1 text-xs font-medium text-muted-foreground sm:inline-flex"><?= (int)$stats['total'] ?> events</span></header><?php if (!$event_rows): ?><div class="flex flex-col items-center justify-center gap-2 p-10 text-center text-sm text-muted-foreground"><p class="m-0">No event listeners are registered.</p></div><?php else: ?><div class="table-toolbar flex justify-end border-b border-border px-5 py-3 max-[640px]:px-4"><label class="relative block w-72 max-w-full"><span class="sr-only">Search events</span><svg class="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" viewBox="0 0 24 24" aria-hidden="true" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg><input class="min-h-9 w-full rounded-md border border-input bg-card py-2 pl-8 pr-3 text-xs text-foreground shadow-sm outline-none transition-colors placeholder:text-muted-foreground focus:border-ring focus:ring-2 focus:ring-ring/20" type="search" placeholder="Search event codes..." aria-label="Search events" data-table-filter="events"></label></div><div class="overflow-x-auto"><table class="w-full min-w-[48rem] border-collapse text-sm" data-table="events"><thead class="bg-muted/40"><tr class="border-b border-border text-left"><th class="px-5 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground max-[640px]:px-4">Event</th><th class="px-4 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">Source</th><th class="px-4 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">Listeners</th><th class="px-4 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">Status</th><th class="px-5 py-2.5 text-end text-[11px] font-semibold uppercase tracking-wide text-muted-foreground max-[640px]:px-4">Action</th></tr></thead><tbody><?php foreach ($event_rows as $event): ?><tr class="border-b border-border transition-colors hover:bg-muted/40"><td class="px-5 py-3.5 max-[640px]:px-4"><div class="grid gap-0.5"><strong class="font-mono text-xs font-medium text-foreground"><?= $e($event['code']) ?></strong><span class="text-xs text-muted-foreground"><?= $e($event['event']) ?><?= $event['description'] !== '' ? ' · ' . $e($event['description']) : '' ?></span></div></td><td class="px-4 py-3.5 text-xs text-muted-foreground"><?= $e($event['extension']) ?></td><td class="px-4 py-3.5 text-xs text-muted-foreground"><?= (int)$event['source_count'] ?></td><td class="px-4 py-3.5"><span class="inline-flex items-center gap-1.5 text-xs font-medium <?= $event['is_core'] ? 'text-primary' : ($event['enabled'] && $event['loaded'] ? 'text-emerald-600 dark:text-emerald-400' : ($event['enabled'] ? 'text-amber-700 dark:text-amber-300' : 'text-muted-foreground')) ?>"><span class="h-1.5 w-1.5 rounded-full <?= $event['is_core'] ? 'bg-primary' : ($event['enabled'] && $event['loaded'] ? 'bg-emerald-500' : ($event['enabled'] ? 'bg-amber-500' : 'bg-muted-foreground/50')) ?>"></span><?= $e($event['status_label']) ?></span></td><td class="px-5 py-3.5 text-end max-[640px]:px-4"><?php if (!$event['is_core']): ?><form method="post" class="inline-flex"><input type="hidden" name="csrf_token" value="<?= $e($csrf) ?>"><input type="hidden" name="event" value="<?= $e($event['code']) ?>"><input type="hidden" name="enabled" value="<?= $event['enabled'] ? '0' : '1' ?>"><button type="submit" class="inline-flex h-8 items-center justify-center rounded-md border border-border bg-card px-2.5 text-xs font-semibold text-foreground transition-colors hover:bg-accent hover:text-accent-foreground"><?= $event['enabled'] ? 'Disable' : 'Enable' ?></button></form><?php else: ?><span class="text-xs text-muted-foreground">Built in</span><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></section>

  <div class="grid grid-cols-2 gap-5 max-[900px]:grid-cols-1"><section id="define-event" class="overflow-hidden rounded-xl border border-border bg-card shadow-sm max-[640px]:rounded-lg"><header class="border-b border-border px-5 py-4 max-[640px]:px-4"><p class="m-0 text-xs font-semibold uppercase tracking-wide text-muted-foreground">Custom event</p><h2 class="mt-1 text-base font-semibold text-foreground">Define a signal</h2><p class="mt-1 text-xs leading-5 text-muted-foreground">Create a stable event name for your application or extension.</p></header><form method="post" class="grid gap-4 px-5 py-5 max-[640px]:px-4"><input type="hidden" name="csrf_token" value="<?= $e($csrf) ?>"><input type="hidden" name="action" value="create"><div class="grid gap-1.5"><label class="text-xs font-medium text-foreground" for="event-name">Event name</label><input class="min-h-9 w-full rounded-md border border-input bg-card px-2.5 py-2 text-sm text-foreground shadow-sm outline-none focus:border-ring focus:ring-2 focus:ring-ring/20" id="event-name" name="event_name" pattern="[a-z][a-z0-9_.-]{2,80}" placeholder="content.published" required><p class="m-0 text-xs leading-5 text-muted-foreground">Use a stable lowercase name.</p></div><div class="grid gap-1.5"><label class="text-xs font-medium text-foreground" for="event-description">Description</label><input class="min-h-9 w-full rounded-md border border-input bg-card px-2.5 py-2 text-sm text-foreground shadow-sm outline-none focus:border-ring focus:ring-2 focus:ring-ring/20" id="event-description" name="description" maxlength="180" placeholder="Runs after a page becomes publishable."></div><button class="inline-flex min-h-9 w-fit items-center justify-center gap-2 rounded-md border border-primary bg-primary px-3.5 py-2 text-sm font-semibold text-primary-foreground transition-colors hover:bg-primary/90" type="submit"><svg class="h-4 w-4" viewBox="0 0 24 24" aria-hidden="true" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 5v14M5 12h14"/></svg><span>Add event</span></button></form></section><section class="overflow-hidden rounded-xl border border-border bg-card shadow-sm max-[640px]:rounded-lg"><header class="border-b border-border px-5 py-4 max-[640px]:px-4"><p class="m-0 text-xs font-semibold uppercase tracking-wide text-muted-foreground">Developer diagnostic</p><h2 class="mt-1 text-base font-semibold text-foreground">Test an event</h2><p class="mt-1 text-xs leading-5 text-muted-foreground">Dispatch a registered event synchronously with a JSON payload.</p></header><form method="post" class="grid gap-4 px-5 py-5 max-[640px]:px-4"><input type="hidden" name="csrf_token" value="<?= $e($csrf) ?>"><input type="hidden" name="action" value="test"><div class="grid gap-1.5"><label class="text-xs font-medium text-foreground" for="event-test-code">Event code</label><select class="min-h-9 w-full cursor-pointer rounded-md border border-input bg-card px-2.5 py-2 text-sm text-foreground shadow-sm outline-none focus:border-ring focus:ring-2 focus:ring-ring/20" id="event-test-code" name="event" required><option value="">Choose an event</option><?php foreach ($events as $event): ?><option value="<?= $e($event['code']) ?>" <?= empty($event['loaded']) && $event['extension'] !== 'core' ? 'disabled' : '' ?>><?= $e($event['code']) ?></option><?php endforeach; ?></select></div><div class="grid gap-1.5"><label class="text-xs font-medium text-foreground" for="event-test-payload">Payload JSON</label><textarea class="min-h-24 w-full resize-y rounded-md border border-input bg-card px-2.5 py-2 text-sm font-mono text-foreground shadow-sm outline-none focus:border-ring focus:ring-2 focus:ring-ring/20" id="event-test-payload" name="payload" required>{}</textarea><p class="m-0 text-xs leading-5 text-muted-foreground">The payload must be a JSON object.</p></div><button class="inline-flex min-h-9 w-fit items-center justify-center gap-2 rounded-md border border-primary bg-primary px-3.5 py-2 text-sm font-semibold text-primary-foreground transition-colors hover:bg-primary/90" type="submit"><svg class="h-4 w-4" viewBox="0 0 24 24" aria-hidden="true" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14M12 5l7 7-7 7"/></svg><span>Dispatch test</span></button></form></section></div>
